class Problem {
    // You are given an array array list of two strings, both strings consist of open
    // parentheses '(' or close parentheses ')' only.
    // Your job is to check if it is possible to concatenate the two strings in
    // some order, that the resulting string will be good.
    // A string S is considered to be good if and only if all parentheses in S
    // are balanced. For example: the string '(())()' is good, while the string
    // '())' is not.
    // Return 'Yes' if there's a way to make a good string, and return 'No' otherwise.
    // Examples:
    // >>> matchParens((new ArrayList<String>(Arrays.asList((String)"()(", (String)")"))))
    // ("Yes")
    // >>> matchParens((new ArrayList<String>(Arrays.asList((String)")", (String)")"))))
    // ("No")
    public static String matchParens(ArrayList<String> lst) {

completion:
        if (lst == null || lst.size() != 2) {
            return "No";
        }

        String first = lst.get(0);
        String second = lst.get(1);

        if (first.length() + second.length() % 2 == 1) {
            return "No";
        }

        for (int i = 0; i <= first.length(); i++) {
            String left = first.substring(0, i);
            String right = first.substring(i);
            if (isBalanced(left + second + right)) {
                return "Yes";
            }
        }

        return "No";
    }

    private static boolean isBalanced(String s) {
        Stack<Character> stack = new Stack<>();
        for (char c : s.toCharArray()) {
            if (c == '(') {
                stack.push(c);
            } else if (c == ')') {
                if (stack.isEmpty() || stack.peek() != '(') {
                    return false;
                }
                stack.pop();
            }
        }
        return stack.isEmpty();
    }

    public static void main(String[] args) {
        System.out.println(matchParens(new ArrayList<>(Arrays.asList("()(", ")")))); // Output: Yes
        System.out.println(matchParens(new ArrayList<>(Arrays.asList(")", ")"))));   // Output: No
    }
}

